import org.springframework.stereotype.*;
import org.springframework.boot.test.context.SpringBootTest;
import static org.junit.jupiter.api.Assertions.*;
import org.junit.jupiter.api.*;

@Service
class PaymentValidator {
    void validate(long amount) {
        if (amount <= 0) throw new IllegalArgumentException("Amount must be positive, got: " + amount);
        if (amount > 1_000_000) throw new IllegalArgumentException("Amount exceeds max: " + amount);
    }
}

@SpringBootTest
class PaymentValidatorBoundaryTest {
    @org.springframework.beans.factory.annotation.Autowired
    PaymentValidator validator;

    // Boundary test 1: exactly 0 → invalid (kills ConditionalBoundary mutation: <= becomes <)
    @Test void amount_zero_throws() {
        assertThrows(IllegalArgumentException.class, () -> validator.validate(0));
    }

    // Boundary test 2: exactly 1 → valid (first valid value)
    @Test void amount_one_valid() {
        assertDoesNotThrow(() -> validator.validate(1));
    }

    // Boundary test 3: exactly 1_000_000 → valid (upper boundary inclusive)
    @Test void amount_max_valid() {
        assertDoesNotThrow(() -> validator.validate(1_000_000));
    }

    // Boundary test 4: 1_000_001 → invalid (kills ConditionalBoundary mutation: > becomes >=)
    @Test void amount_overMax_throws() {
        assertThrows(IllegalArgumentException.class, () -> validator.validate(1_000_001));
    }
}

import org.springframework.stereotype.*;
import org.mockito.*;
import org.mockito.junit.jupiter.MockitoExtension;
import org.junit.jupiter.api.*;
import org.junit.jupiter.api.extension.ExtendWith;
import static org.mockito.Mockito.*;
import static org.junit.jupiter.api.Assertions.*;

interface PayValidator { void validate(long amount); }
interface PayAuditLogger { void log(String merchantId, long amount); }
interface PayNotificationService { void send(String merchantId); }

@ExtendWith(MockitoExtension.class)
class PaymentProcessorMutationTest {

    @Mock PayValidator validator;
    @Mock PayAuditLogger auditLogger;
    @Mock PayNotificationService notificationService;

    PaymentProcessor processor;

    @BeforeEach void setup() {
        processor = new PaymentProcessor(validator, auditLogger, notificationService);
    }

    @Test void process_callsAllDependencies() {
        // Act:
        processor.process("MRC-001", 5000L);

        // Kill VoidMethodCall mutations — verify each call happened:
        verify(validator).validate(5000L);                   // kills: removed validate() call
        verify(auditLogger).log("MRC-001", 5000L);           // kills: removed auditLogger.log() call
        verify(notificationService).send("MRC-001");         // kills: removed notificationService.send()
    }

    @Test void process_withZeroAmount_validatorCalled() {
        doThrow(new IllegalArgumentException("invalid")).when(validator).validate(0L);
        assertThrows(IllegalArgumentException.class, () -> processor.process("MRC-001", 0L));
        verify(validator).validate(0L); // validator still called for zero
        verifyNoInteractions(auditLogger); // audit NOT called on invalid
        verifyNoInteractions(notificationService); // notification NOT called on invalid
    }
}

class PaymentProcessor {
    private final PayValidator validator;
    private final PayAuditLogger auditLogger;
    private final PayNotificationService notificationService;

    PaymentProcessor(PayValidator v, PayAuditLogger a, PayNotificationService n) {
        validator = v; auditLogger = a; notificationService = n;
    }

    public void process(String merchantId, long amount) {
        validator.validate(amount);
        auditLogger.log(merchantId, amount);
        notificationService.send(merchantId);
    }
}

import org.springframework.stereotype.*;
import org.springframework.boot.test.context.SpringBootTest;
import org.springframework.beans.factory.annotation.Autowired;
import static org.junit.jupiter.api.Assertions.*;
import org.junit.jupiter.api.*;

enum MerchantTier { STANDARD, PREMIUM }

@Service
class PaymentRouter {
    String route(long amount, MerchantTier tier) {
        if (amount > 100_000 && tier == MerchantTier.PREMIUM) return "HDFC_PREMIUM";
        if (amount > 100_000) return "VISA_ENTERPRISE";
        if (tier == MerchantTier.PREMIUM) return "HDFC_STANDARD";
        return "VISA_STANDARD";
    }
}

@SpringBootTest
class PaymentRouterMutationTest {
    @Autowired PaymentRouter router;

    // Branch 1: large amount + PREMIUM → HDFC_PREMIUM
    @Test void largeAmount_premium_hdfcPremium() {
        assertEquals("HDFC_PREMIUM", router.route(100_001L, MerchantTier.PREMIUM));
    }

    // Branch 2: large amount + STANDARD → VISA_ENTERPRISE
    @Test void largeAmount_standard_visaEnterprise() {
        assertEquals("VISA_ENTERPRISE", router.route(100_001L, MerchantTier.STANDARD));
    }

    // Branch 3: small amount + PREMIUM → HDFC_STANDARD
    @Test void smallAmount_premium_hdfcStandard() {
        assertEquals("HDFC_STANDARD", router.route(100_000L, MerchantTier.PREMIUM));
    }

    // Branch 4: small amount + STANDARD → VISA_STANDARD (default)
    @Test void smallAmount_standard_visaStandard() {
        assertEquals("VISA_STANDARD", router.route(100_000L, MerchantTier.STANDARD));
    }

    // Boundary: exactly 100_000 is NOT > 100_000 (kills ConditionalBoundary mutation)
    @Test void exactlyBoundary_standard_visaStandard() {
        assertEquals("VISA_STANDARD", router.route(100_000L, MerchantTier.STANDARD));
    }

    // Boundary: 100_001 IS > 100_000 (kills ConditionalBoundary on both sides)
    @Test void justAboveBoundary_premium_hdfcPremium() {
        assertEquals("HDFC_PREMIUM", router.route(100_001L, MerchantTier.PREMIUM));
    }
}

