import org.springframework.stereotype.*;
import org.springframework.boot.test.context.SpringBootTest;
import org.springframework.beans.factory.annotation.Autowired;
import static org.junit.jupiter.api.Assertions.*;
import org.junit.jupiter.api.*;
import java.util.Set;

@Service
class PaymentService {
    private static final Set<String> VALID_GATEWAYS = Set.of("HDFC", "VISA", "RUPAY");
    private static final long MIN = 1L;
    private static final long MAX = 1_000_000L;

    String createPayment(String merchantId, long amount, String gateway) {
        if (merchantId == null || merchantId.isBlank())
            throw new IllegalArgumentException("merchantId required");
        if (amount < MIN || amount > MAX)
            throw new IllegalArgumentException("amount must be " + MIN + "-" + MAX + ", got: " + amount);
        if (!VALID_GATEWAYS.contains(gateway))
            throw new IllegalArgumentException("invalid gateway: " + gateway);
        return "PAY-" + merchantId + "-" + amount;
    }
}

@SpringBootTest
class PaymentServiceMutationTest {
    @Autowired PaymentService svc;

    @Test void happyPath_returns_paymentId() {
        String id = svc.createPayment("MRC-001", 5000L, "HDFC");
        assertTrue(id.startsWith("PAY-MRC-001"));
        assertTrue(id.contains("5000"));
    }
    @Test void blankMerchant_throws() {
        assertThrows(IllegalArgumentException.class, () -> svc.createPayment("", 500L, "VISA"));
    }
    @Test void nullMerchant_throws() {
        assertThrows(IllegalArgumentException.class, () -> svc.createPayment(null, 500L, "VISA"));
    }
    @Test void amountZero_throws() {
        assertThrows(IllegalArgumentException.class, () -> svc.createPayment("M1", 0L, "HDFC"));
    }
    @Test void amountOne_valid() {
        assertDoesNotThrow(() -> svc.createPayment("M1", 1L, "HDFC"));
    }
    @Test void amountMax_valid() {
        assertDoesNotThrow(() -> svc.createPayment("M1", 1_000_000L, "HDFC"));
    }
    @Test void amountOverMax_throws() {
        assertThrows(IllegalArgumentException.class, () -> svc.createPayment("M1", 1_000_001L, "HDFC"));
    }
    @Test void invalidGateway_throws() {
        assertThrows(IllegalArgumentException.class, () -> svc.createPayment("M1", 500L, "UNKNOWN"));
    }
    @Test void allValidGateways_work() {
        for (String gw : Set.of("HDFC","VISA","RUPAY")) {
            assertDoesNotThrow(() -> svc.createPayment("M1", 500L, gw));
        }
    }
}

import org.springframework.stereotype.*;
import org.mockito.*;
import org.mockito.junit.jupiter.MockitoExtension;
import org.junit.jupiter.api.*;
import org.junit.jupiter.api.extension.ExtendWith;
import org.springframework.boot.test.context.SpringBootTest;
import org.springframework.beans.factory.annotation.Autowired;
import static org.mockito.Mockito.*;
import static org.junit.jupiter.api.Assertions.*;

interface GatewayAudit { void recordRoute(String gateway, String merchantId); }

@Service
class RzpPaymentRouter {
    private final GatewayAudit audit;
    RzpPaymentRouter(GatewayAudit a) { audit = a; }

    String route(long amount, MerchantTier tier, String merchantId) {
        String gateway;
        if (amount > 100_000 && tier == MerchantTier.PREMIUM) gateway = "HDFC_PREMIUM";
        else if (amount > 100_000) gateway = "VISA_ENTERPRISE";
        else if (tier == MerchantTier.PREMIUM) gateway = "HDFC_STANDARD";
        else gateway = "VISA_STANDARD";
        audit.recordRoute(gateway, merchantId);
        return gateway;
    }
}

@ExtendWith(MockitoExtension.class)
class RzpRouterMutationTest {
    @Mock GatewayAudit audit;
    RzpPaymentRouter router;
    @BeforeEach void setup() { router = new RzpPaymentRouter(audit); }

    // Branch coverage + boundary:
    @Test void branch1_largePremium() { assertEquals("HDFC_PREMIUM", router.route(100_001L, MerchantTier.PREMIUM, "M1")); }
    @Test void branch2_largeStandard() { assertEquals("VISA_ENTERPRISE", router.route(100_001L, MerchantTier.STANDARD, "M2")); }
    @Test void branch3_smallPremium() { assertEquals("HDFC_STANDARD", router.route(100_000L, MerchantTier.PREMIUM, "M3")); }
    @Test void branch4_smallStandard() { assertEquals("VISA_STANDARD", router.route(100_000L, MerchantTier.STANDARD, "M4")); }

    // Boundary tests (kill ConditionalBoundary on > 100_000):
    @Test void exactlyBoundary_notLarge() { assertEquals("HDFC_STANDARD", router.route(100_000L, MerchantTier.PREMIUM, "M5")); }
    @Test void justAboveBoundary_large() { assertEquals("HDFC_PREMIUM", router.route(100_001L, MerchantTier.PREMIUM, "M6")); }

    // Kill VoidMethodCall mutation on audit.recordRoute():
    @Test void audit_calledWithCorrectGateway() {
        router.route(100_001L, MerchantTier.PREMIUM, "MRC-001");
        verify(audit).recordRoute("HDFC_PREMIUM", "MRC-001");
    }
    @Test void audit_calledForEveryRoute() {
        router.route(50_000L, MerchantTier.STANDARD, "MRC-002");
        verify(audit).recordRoute("VISA_STANDARD", "MRC-002");
    }
}

import org.springframework.stereotype.*;
import org.springframework.boot.test.context.SpringBootTest;
import org.springframework.beans.factory.annotation.Autowired;
import static org.junit.jupiter.api.Assertions.*;
import org.junit.jupiter.api.*;

@Service
class ZerodhaOrderEligibility {
    boolean eligible(int age, boolean kycCompleted, long balance, int riskScore) {
        return age >= 18 && kycCompleted && balance >= 10_000 && riskScore <= 7;
    }
}

@SpringBootTest
class EligibilityMutationTest {
    @Autowired ZerodhaOrderEligibility svc;

    // Happy path: all conditions true
    @Test void allTrue_eligible() {
        assertTrue(svc.eligible(25, true, 50_000L, 5));
    }

    // Each condition individually false:
    @Test void underage_notEligible() { assertFalse(svc.eligible(17, true, 50_000L, 5)); }
    @Test void noKyc_notEligible() { assertFalse(svc.eligible(25, false, 50_000L, 5)); }
    @Test void lowBalance_notEligible() { assertFalse(svc.eligible(25, true, 9_999L, 5)); }
    @Test void highRisk_notEligible() { assertFalse(svc.eligible(25, true, 50_000L, 8)); }

    // Boundary: age >= 18 (kills ConditionalBoundary: >= → >)
    @Test void age18_eligible() { assertTrue(svc.eligible(18, true, 50_000L, 5)); }
    @Test void age17_notEligible() { assertFalse(svc.eligible(17, true, 50_000L, 5)); }

    // Boundary: balance >= 10_000
    @Test void balanceExact10000_eligible() { assertTrue(svc.eligible(25, true, 10_000L, 5)); }
    @Test void balance9999_notEligible() { assertFalse(svc.eligible(25, true, 9_999L, 5)); }

    // Boundary: riskScore <= 7
    @Test void riskScore7_eligible() { assertTrue(svc.eligible(25, true, 50_000L, 7)); }
    @Test void riskScore8_notEligible() { assertFalse(svc.eligible(25, true, 50_000L, 8)); }
}

import org.springframework.stereotype.*;
import org.mockito.*;
import org.mockito.junit.jupiter.MockitoExtension;
import org.junit.jupiter.api.*;
import org.junit.jupiter.api.extension.ExtendWith;
import org.springframework.boot.test.context.SpringBootTest;
import org.springframework.beans.factory.annotation.Autowired;
import static org.mockito.Mockito.*;
import static org.junit.jupiter.api.Assertions.*;
import java.util.Set;

interface SynthAudit { void log(String event, String merchantId); }

@Service
class SynthValidator {
    private final SynthAudit audit;
    private static final Set<String> GWS = Set.of("HDFC", "VISA");
    SynthValidator(SynthAudit a) { audit = a; }
    String validate(String merchantId, long amount, String gateway) {
        if (merchantId == null || merchantId.isBlank()) throw new IllegalArgumentException("merchant required");
        if (amount < 1 || amount > 100_000) throw new IllegalArgumentException("bad amount: " + amount);
        if (!GWS.contains(gateway)) throw new IllegalArgumentException("bad gateway: " + gateway);
        audit.log("validated", merchantId);
        return "OK-" + merchantId;
    }
}

@ExtendWith(MockitoExtension.class)
class SynthMutationTest {
    @Mock SynthAudit audit;
    SynthValidator svc;
    @BeforeEach void setup() { svc = new SynthValidator(audit); }

    @Test void happy_path() { assertEquals("OK-MRC-001", svc.validate("MRC-001", 500L, "HDFC")); }
    @Test void null_merchant_throws() { assertThrows(IllegalArgumentException.class, () -> svc.validate(null, 500L, "VISA")); }
    @Test void blank_merchant_throws() { assertThrows(IllegalArgumentException.class, () -> svc.validate("", 500L, "VISA")); }
    @Test void amount_zero_throws() { assertThrows(IllegalArgumentException.class, () -> svc.validate("M1", 0L, "HDFC")); }
    @Test void amount_one_valid() { assertDoesNotThrow(() -> svc.validate("M1", 1L, "HDFC")); }
    @Test void amount_max_valid() { assertDoesNotThrow(() -> svc.validate("M1", 100_000L, "HDFC")); }
    @Test void amount_overMax_throws() { assertThrows(IllegalArgumentException.class, () -> svc.validate("M1", 100_001L, "HDFC")); }
    @Test void bad_gateway_throws() { assertThrows(IllegalArgumentException.class, () -> svc.validate("M1", 500L, "AMEX")); }
    // Kill VoidMethodCall on audit.log():
    @Test void audit_called_on_success() {
        svc.validate("MRC-001", 500L, "HDFC");
        verify(audit).log("validated", "MRC-001");
    }
    @Test void audit_NOT_called_on_failure() {
        try { svc.validate("MRC-001", 0L, "HDFC"); } catch (Exception ignored) {}
        verifyNoInteractions(audit);
    }
}
